// ── Receive payload from parent workflow ─────────────────
// Expected input:
// {
//   title: string,         — project/task name
//   content: string,       — the main output/result
//   task_type: string,     — research | writing | coding | consulting | quick
//   from_number: string,   — Telegram ID or unique identifier that triggered this
//   github_repo: string,   — optional: repo name to commit to
//   github_path: string,   — optional: file path in repo
//   notion_db_id: string   — optional: override default Notion DB
// }

const input = $input.first().json;

const title = input.title || 'Untitled Task';
const content = input.content || '';
const task_type = input.task_type || 'general';
const timestamp = new Date().toISOString();
const date_str = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
const slug = title.toLowerCase().replace(/[^a-z0-9]+/g, '-').substring(0, 50);

return [{
  json: {
    title,
    content,
    task_type,
    timestamp,
    date_str,
    slug,
    from_number: input.from_number || 'unknown',
    github_repo: input.github_repo || 'boubacar-agent-outputs',
    github_path: input.github_path || `outputs/${task_type}/${slug}.md`,
    notion_db_id: input.notion_db_id || 'YOUR_NOTION_DB_ID_HERE',
    drive_folder_id: input.drive_folder_id || 'YOUR_GOOGLE_DRIVE_FOLDER_ID_HERE',
    markdown_content: `# ${title}\n\n**Date:** ${date_str}\n**Type:** ${task_type}\n**Triggered by:** Telegram\n\n---\n\n${content}\n`
  }
}];

// ── Collect results from all three saves ─────────────────
const github_result = $('Save to GitHub').first()?.json;
const drive_result = $('Save to Google Drive').first()?.json;
const notion_result = $('Log to Notion').first()?.json;

const github_url = github_result?.content?.html_url || 'GitHub saved';
const drive_url = drive_result?.webViewLink || 'Drive saved';
const notion_url = notion_result?.url || 'Notion logged';

return [{
  json: {
    success: true,
    github_url,
    drive_url,
    notion_url,
    summary: `Saved everywhere:\nGitHub: ${github_url}\nDrive: ${drive_url}\nNotion: ${notion_url}`
  }
}];
